SELECT * FROM catalog_sales, inventory, warehouse, item, customer_demographics, household_demographics, date_dim d1, date_dim d2, date_dim d3, promotion, catalog_returns WHERE d1.d_week_seq = d2.d_week_seq AND inv_quantity_on_hand < cs_quantity AND d1.d_year = 1998 AND (cs_item_sk = inv_item_sk) AND (w_warehouse_sk = inv_warehouse_sk) AND (i_item_sk = cs_item_sk) AND (cs_bill_cdemo_sk = cd_demo_sk) AND (cs_bill_hdemo_sk = hd_demo_sk) AND (cs_sold_date_sk = d1.d_date_sk) AND (inv_date_sk = d2.d_date_sk) AND (cs_ship_date_sk = d3.d_date_sk) AND (cs_promo_sk = p_promo_sk) AND (cr_item_sk = cs_item_sk AND cr_order_number = cs_order_number);
